import React, { useRef, useEffect, useState } from "react";
import type { ICollapseProps } from "@lmb-it/kitsconcerto-types";

const Collapse: React.FC<ICollapseProps> = ({
                                                isOpen,
                                                children,
                                                duration = 300,
                                            }) => {
    const contentRef = useRef<HTMLDivElement | null>(null);
    const [height, setHeight] = useState<number>(0);
    const [shouldRenderAuto, setShouldRenderAuto] = useState(false);

    useEffect(() => {
        const el = contentRef.current;
        if (!el) return;

        if (isOpen) {
            // Reset to actual height
            const scrollHeight = el.scrollHeight;
            setShouldRenderAuto(false);
            setHeight(scrollHeight);

            // After transition, allow height:auto to handle dynamic content
            const timer = setTimeout(() => {
                setShouldRenderAuto(true);
            }, duration);
            return () => clearTimeout(timer);
        } else {
            // From auto to fixed height before collapsing
            setShouldRenderAuto(false);
            const currentHeight = el.offsetHeight;
            setHeight(currentHeight);

            // Use next frame to animate collapse
            requestAnimationFrame(() => {
                setHeight(0);
            });
        }
    }, [isOpen, duration]);

    return (
        <div
            style={{
                height: shouldRenderAuto && isOpen ? "auto" : `${height}px`,
                overflow: "hidden",
                transition: `height ${duration}ms ease`,
            }}
        >
            <div ref={contentRef}>
                {children}
            </div>
        </div>
    );
};

export default Collapse;
